scripts.code:
Connect-MgGraph -Scopes "UserAuthenticationMethod.Read.All"
$users = Get-MgUser -All
$results = foreach($u in $users){
  $methods = Get-MgUserAuthenticationMethod -UserId $u.Id
  [PSCustomObject]@{
    UPN = $u.UserPrincipalName
    MFA = ($methods.Count -gt 1)
  }
}
$results | Export-Csv -Path .\mfa_report.csv -NoTypeInformation

$nsgs = Get-AzNetworkSecurityGroup
foreach($nsg in $nsgs){
  $nsg.SecurityRules | Where-Object {
    $_.Access -eq "Allow" -and
    $_.Direction -eq "Inbound" -and
    $_.SourceAddressPrefix -eq "*"
  } | Select-Object Name, DestinationPortRange
}
